solution: class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int res = 0;
        int left = 0, right = n - 1;
        while (left < right) {
            int l = left, r = right;
            while (l < r && s[l] != s[r]) --r;
            if (l == r) {
                swap(s[l], s[l + 1]);
                ++res;
                continue;
            }
            while (r < right) {
                swap(s[r], s[r + 1]);
                ++res;
                ++r;
            }
            ++left;
            --right;
        }
        return res;
    }
};
